head.script:
        scwin.vCurDate = "";

        scwin.onpageload = function() {
            scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
            scwin.f_Set("INIT");
        };

         scwin.onUdcCompleted = function() {
             udc_adpt.setInitDate(scwin.vCurDate, scwin.vCurDate);

             //$c.gus.cfDisableObjects([ed_ctrtClntNo, txt_ctrtClntNm]);
            //  udc_adpt.setInitDate("20250313", "20250313");
            //  ed_ctrtClntNo.setValue("253330");
         };

        scwin.f_Set = function(gubun) {
            switch (gubun) {
                case "INIT":
                    lc_odrSearchCd.setValue("0");
                    scwin.f_setDesign("0");
                    break;
            }
        };

        scwin.f_defaultValue = function() {
            chb_subSumYn.checkAll(false);
            udc_adpt.setInitDate(scwin.vCurDate, scwin.vCurDate);
        };

        scwin.f_FieldClear = function() {
            $c.gus.cfInitObjects([lc_odrSearchCd, ed_ctrtClntNo, txt_ctrtClntNm, ica_adptFrom, ica_adptTo, ica_rsltsFrom, ica_rsltsTo]);
        };

        scwin.f_Retrieve = async function() {
            // 필수항목 체크
            //요청거래처명 먼저 체크 
            if( await $c.gus.cfIsNull(txt_ctrtClntNm.getValue())){
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["요청거래처명"]);
                txt_ctrtClntNm.focus();
                return;
            }

            let chk11 = await $c.gus.cfValidate([tbl_search]);
            if (!chk11) {return;}

            let adptFromVal = ica_adptFrom.getValue();
            let adptToVal = ica_adptTo.getValue();

            if (!$c.gus.cfIsAfterDate(adptFromVal, adptToVal)) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
                ica_adptFrom.focus();
                return;
            }

            if (!$c.gus.cfIsAfterDate(adptFromVal, adptToVal)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
                ica_adptFrom.focus();
                return;
            }

            if (chb_subSumYn.getValue() != "") {
                ds_results.setOption("subsumExpr", "odrNo");
            } else {
                ds_results.setOption("subsumExpr", "");
            }

            await $c.sbm.execute(sbm_retrieve);
        };

        scwin.btn_Srch_onclick = function(e) {
            scwin.f_Retrieve();
        };

        scwin.sbm_retrieve_submitdone = async function(e) {
            let rowCount = ds_results.getRowCount();
            if (rowCount == 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            }
            totalRows.setValue(rowCount);


           let chksubsumYn = chb_subSumYn.getValue();
            if("Y"==chksubsumYn){//소계 포함인 경우 subtotal 활성화
                gr_results.setSubtotalVisible(true);
                gr_resultsSum.setSubtotalVisible(true);
            }else{
                gr_results.setSubtotalVisible(false);
                gr_resultsSum.setSubtotalVisible(false);
            }
        };

        scwin.sbm_retrieve_submiterror = function(e) {
            $c.gus.cfShowError(e);
        };

        scwin.lc_odrSearchCd_onchange = function(info) {
            ds_results.removeAll();
            gr_results.initGrid();
            gr_resultsSum.initGrid();
            gr_results.setVisibleRowNum(15);
            gr_resultsSum.setVisibleRowNum(15);
            scwin.f_setDesign(info.newValue);

            totalRows.setValue(0);
        };

        scwin.ed_ctrtClntNo_onblur = function() {
            scwin.f_chkOpenCommonPopUp(ed_ctrtClntNo, txt_ctrtClntNm, 0);
        };

        scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
            udc_ctrtClntNo.setSelectId("retrieveClntInfo2"); // XML상의 SELECT ID
            udc_ctrtClntNo.cfCommonPopUp(scwin.callbackCtrtClnt // 콜백 함수
            , pCode // 화면에서의 ??? Code Element의 Value
            , pName // 화면에서의 ??? Name Element의 Value
            , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
            , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
            , null // Title순서
            , null // 보여주는 각 컬럼들의 폭
            , null // 컬럼중에서 숨기는 컬럼 지정
            , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
            , null // POP-UP뛰을때 원도우의 사용자 정의 폭
            , null // POP-UP뛰을때 원도우의 사용자 정의 높이
            , null // 윈도우 위치 Y좌표
            , null // 윈도우 위치 X좌표
            , null // 중복체크여부 ("F")
            , pAllSearch // 전체검색허용여부 ("F")
            , "요청거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
        };

        scwin.callbackCtrtClnt = function(rtnList) {
            $c.gus.cfSetReturnValue(rtnList, ed_ctrtClntNo, txt_ctrtClntNm);
        };

        scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode, isRetrieveValue) {
            if ((isRetrieveValue == null) && !$c.gus.cfCanOpenPopup(inObj, pairObj)) {
                return;
            }

            $c.gus.cfClearPairObj(pairObj);

            let pVal = $c.gus.cfGetValue(inObj);

            if (isCode == null || isCode == true) {
                scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
            } else {
                scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
            }
        };

        scwin.txt_ctrtClntNm_onchange = function(e) {
            scwin.f_chkOpenCommonPopUp(txt_ctrtClntNm, ed_ctrtClntNo, 0, false);
        };

        scwin.udc_ctrtClnt_onClick = function() {
            scwin.f_openCommonPopUp(0, ed_ctrtClntNo.getValue(), txt_ctrtClntNm.getValue(), 'F', 'F');
        };

        scwin.f_setDesign = function(index) {
            if (index == "0") {
                gr_results.setStyle("display", "block");
                gr_resultsSum.setStyle("display", "none");
                udc_topGrdBtn.setGridId("gr_results");
            } else {
                gr_results.setStyle("display", "none");
                gr_resultsSum.setStyle("display", "block");
                udc_topGrdBtn.setGridId("gr_resultsSum");
            }
        };

        scwin.f_Excel = function() {
            let index = lc_odrSearchCd.getValue();

            if (index == "0") {
                $c.data.downloadGridViewExcel(gr_results, {
                    fileName: "동부제철 기간별 운송실적 현황.xlsx",
                    sheetName: "동부제철 기간별 운송실적 현황"
                });
            } else {
                $c.data.downloadGridViewExcel(gr_resultsSum, {
                    fileName: "동부제철 소속별 운송실적 현황.xlsx",
                    sheetName: "동부제철 소속별 운송실적 현황"
                });
            }
        };

// scwin.udc_ctrtClntNo_onblurCodeEvent = function (e) {
//     scwin.f_chkOpenCommonPopUp(ed_ctrtClntCd, txt_ctrtClntNm, 5, true);
// };

// scwin.udc_ctrtClntNo_onblurNameEvent = function (e) {
//     scwin.f_chkOpenCommonPopUp(txt_ctrtClntNm, ed_ctrtClntCd, 5, false);
// };

scwin.udc_ctrtClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(5, ed_ctrtClntNo.getValue(), txt_ctrtClntNm.getValue(), 'F', 'F');
};

scwin.btn_refresh_onclick = function (e) {
    scwin.f_FieldClear();
    scwin.f_defaultValue();
	txt_ctrtClntNm.focus();    

};

scwin.setFormatter = function (d) {
    if (d == 0) return "";
    return Number(d).toLocaleString();
};
